**2. `buildMongoValidator` — the function that constructs the `$jsonSchema` validator (lines 702–740)**

This is the only path that produces validators; `generateMongoSchema` just calls it per standalone entity.

```js
702  function buildMongoValidator(entityName, entityDef, embeddedChildren = []) {
703    const fields = entityDef.fields;
704    const requiredFields = Object.keys(fields).filter(
705      (k) => fields[k].required && !fields[k].pk,
706    );
707    const properties = {};
708    for (const [fieldName, fieldDef] of Object.entries(fields)) {
709      if (fieldDef.pk) {
710        properties[fieldName] = mongoFieldDef(fieldName, fieldDef);
711      } else {
712        properties[fieldName] = mongoFieldDef(fieldName, fieldDef);
713      }
714    }
715    // Add embedded child arrays
716    for (const childName of embeddedChildren) {
717      const childDef = ENTITIES[childName];
718      if (childDef) {
719        const childProps = {};
720        for (const [cf, cd] of Object.entries(childDef.fields)) {
721          if (!cd.fk) childProps[cf] = mongoFieldDef(cf, cd);
722        }
723        properties[childName] = {
724          bsonType: "array",
725          items: {
726            bsonType: "object",
727            properties: childProps,
728          },
729        };
730      }
731    }
732    return {
733      $jsonSchema: {
734        bsonType: "object",
735        required: requiredFields.length > 0 ? requiredFields : undefined,
736        properties,
737      },
738    };
739  }
```

**3. `additionalProperties: false` — not present anywhere in the file**

A search of the entire file finds no occurrence of `additionalProperties`. The validator object returned at lines 732–738 contains only `bsonType`, `required`, and `properties`. There is no `additionalProperties: false` at any level — neither on the top-level document object nor on the embedded child item schemas.

